org.machanism.macha.core.commons.configurator.Configurator config = ...;
org.machanism.machai.project.layout.ProjectLayout layout = ...;

// 1) Create/update bindex.json
new org.machanism.machai.bindex.BindexCreator("openai", config).update(true).processFolder(layout);

// 2) Register
new org.machanism.machai.bindex.BindexRegister("openai", null, config).update(true).processFolder(layout);

// 3) Retrieve
org.machanism.machai.bindex.Picker picker = new org.machanism.machai.bindex.Picker("openai", null, config);
java.util.List<org.machanism.machai.schema.Bindex> selected = picker.pick("Find libraries for server-side logging");

// 4) Assemble prompt input
new org.machanism.machai.bindex.ApplicationAssembly("openai", config, layout.getProjectDir())
    .assembly("Generate an example app using the selected libraries", selected);
